import collegesData from '@/data/colleges.json';
import { College, Stream } from '@/types/college';
import { resolveCollegeMedia } from '@/lib/college-images';

const colleges = (collegesData as College[]).map(resolveCollegeMedia);

export const getColleges = async (filters?: {
  search?: string;
  stream?: Stream;
  location?: string;
  minRating?: number;
}): Promise<College[]> => {
  await new Promise((resolve) => setTimeout(resolve, 500));

  let filtered = [...colleges];

  if (filters?.search) {
    const search = filters.search.toLowerCase();
    filtered = filtered.filter(
      (c) =>
        c.name.toLowerCase().includes(search) ||
        c.location.toLowerCase().includes(search)
    );
  }

  if (filters?.stream) {
    filtered = filtered.filter((c) => c.stream === filters.stream);
  }

  if (filters?.location) {
    filtered = filtered.filter((c) =>
      c.location.toLowerCase().includes(filters.location!.toLowerCase())
    );
  }

  if (filters?.minRating) {
    filtered = filtered.filter((c) => c.rating >= filters.minRating!);
  }

  return filtered;
};

export const getCollegeById = async (id: string): Promise<College | undefined> => {
  await new Promise((resolve) => setTimeout(resolve, 300));
  return colleges.find((c) => c.id === id);
};

export const getCollegesByIds = async (ids: string[]): Promise<College[]> => {
  await new Promise((resolve) => setTimeout(resolve, 300));
  return colleges.filter((c) => ids.includes(c.id));
};

export const predictColleges = async (exam: string, rank: number): Promise<College[]> => {
  await new Promise((resolve) => setTimeout(resolve, 600));
  return colleges.filter((c) => {
    const cutoff = c.cutoffs?.[exam];
    if (!cutoff) return false;
    return rank >= cutoff.min && rank <= cutoff.max * 1.1;
  });
};
